<?php declare(strict_types=1); require_once __DIR__ . '/../vendor/autoload.php'; use App\Database\Database; use App\Models\User; use App\Controllers\UserController; session_start(); $db = Database::getInstance(); $controller = new UserController(); if (isset($_GET['action']) && $_GET['action'] === 'create') { $controller->create(); } $users = $controller->listAll(); $success = isset($_GET['success']); ?>
<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><title>PHP 2015 Modern</title><link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/twitter-bootstrap/3.4.1/css/bootstrap.min.css"></head><body><div class="container"><h1>PHP 2015 - Modern PDO Application</h1><?php if ($success): ?><div class="alert alert-success">User added successfully!</div><?php endif; ?><form method="GET" action="/index.php"><input type="hidden" name="action" value="create"><input type="text" name="name" class="form-control" placeholder="Name" required><input type="email" name="email" class="form-control" placeholder="Email" required><button type="submit" class="btn btn-primary">Add User</button></form><h2>Users</h2><table class="table table-striped"><tr><th>ID</th><th>Name</th><th>Email</th></tr><?php foreach ($users as $user): ?><tr><td><?php echo (int)$user['id']; ?></td><td><?php echo htmlspecialchars($user['name']); ?></td><td><?php echo htmlspecialchars($user['email']); ?></td></tr><?php endforeach; ?></table></div></body></html>